func formatPrice(cents int64, currency string) string {
	symbol := currencySymbol(currency)
	euros := float64(cents) / 100.0
	return fmt.Sprintf("%s%.2f", symbol, euros)
}

func currencySymbol(currency string) string {
	switch currency {
	case "EUR":
		return "€"
	case "USD":
		return "$"
	case "GBP":
		return "£"
	default:
		return currency + " "
	}
}

